#include <stdio.h>
#define MOD 1000000007
long long countPatches(long long N) {
    long long count = 0;
    for (long long i = 1; i * i <= N; i++) {
        if (N % i == 0) {
            long long j = N / i;
            if (i <= j) {
                count = (count + (j - i + 1)) % MOD;
            }
        }
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        printf("%lld\n", countPatches(N));
    }
    return 0;
}

